import type { Goal } from '@motivation/shared';
import type { GoalList } from '../goal-list/goal-list.component.js';
import type { GoalHeaderCard } from '../goal-header-card/goal-header-card.component.js';
import '../goal-list/goal-list.component.js';
import '../goal-header-card/goal-header-card.component.js';

const template = document.createElement('template');
template.innerHTML = `
    <div id="root-view">
        <goal-list id="root-list"></goal-list>
    </div>
    <div id="detail-view" hidden>
        <goal-header-card id="header"></goal-header-card>
        <goal-list id="sub-goal-list"></goal-list>
    </div>
`;

export class GoalNavigator extends HTMLElement {
    private _currentParentId: string | null = null;
    private _allGoals: Goal[] = [];

    private rootView!: HTMLElement;
    private detailView!: HTMLElement;
    private rootList!: GoalList;
    private subGoalList!: GoalList;
    private header!: GoalHeaderCard;

    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
        this.shadowRoot!.appendChild(template.content.cloneNode(true));
        
        this.rootView = this.shadowRoot!.getElementById('root-view')!;
        this.detailView = this.shadowRoot!.getElementById('detail-view')!;
        this.rootList = this.shadowRoot!.getElementById('root-list') as GoalList;
        this.subGoalList = this.shadowRoot!.getElementById('sub-goal-list') as GoalList;
        this.header = this.shadowRoot!.getElementById('header') as GoalHeaderCard;
    }

    get currentParentId(): string | null {
        return this._currentParentId;
    }

    get allGoals(): Goal[] {
        return this._allGoals;
    }

    renderGoals(goals: Goal[]) {
        this._allGoals = goals;
        this.renderCurrentView();
    }

    renderCurrentView() {
        let currentGoal: Goal | undefined;
        let goalsToShow = this._allGoals;

        if (this._currentParentId) {
            currentGoal = this.findGoal(this._allGoals, this._currentParentId);
            if (currentGoal) {
                goalsToShow = currentGoal.sub_goals ?? [];
            } else {
                // Parent deleted or lost
                this._currentParentId = null;
                goalsToShow = this._allGoals;
            }
        }

        if (currentGoal) {
            this.rootView.hidden = true;
            this.detailView.hidden = false;
            
            this.header.dataset.goalId = currentGoal.id;
            this.header.dataset.title = currentGoal.title;
            this.header.dataset.description = currentGoal.description ?? '';
            
            this.subGoalList.goals = goalsToShow;
        } else {
            this.rootView.hidden = false;
            this.detailView.hidden = true;
            
            delete this.header.dataset.goalId;
            delete this.header.dataset.title;
            delete this.header.dataset.description;
            
            this.rootList.goals = goalsToShow;
        }
    }

    findGoal(nodes: Goal[], id: string): Goal | undefined {
        for (const node of nodes) {
            if (node.id === id) return node;
            if (node.sub_goals) {
                const found = this.findGoal(node.sub_goals, id);
                if (found) return found;
            }
        }
        return undefined;
    }

    findParentNode(nodes: Goal[], targetId: string): Goal | null {
        for (const node of nodes) {
            if (node.sub_goals?.some(child => child.id === targetId)) {
                return node;
            }
            if (node.sub_goals) {
                const found = this.findParentNode(node.sub_goals, targetId);
                if (found) return found;
            }
        }
        return null;
    }

    navigateTo(id: string) {
        this._currentParentId = id;
        document.documentElement.classList.remove('back-transition');
        this.renderCurrentView();
    }

    navigateUp() {
        if (!this._currentParentId) return;
        const parent = this.findParentNode(this._allGoals, this._currentParentId);
        this._currentParentId = parent ? parent.id : null;
        document.documentElement.classList.add('back-transition');
        this.renderCurrentView();
    }
}

if (!customElements.get('goal-navigator')) {
    customElements.define('goal-navigator', GoalNavigator);
}
