import type { Goal } from '@motivation/shared';
import stylesText from './goal-item.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import {
    createGoalNavigateEvent,
    createGoalChangeStatusEvent,
} from '../../goal-events.js';
import './goal-cube/goal-cube.component.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="goal-item" id="item">
        <div class="status-indicator" id="status-indicator"></div>
        <div class="content">
            <h3 class="title" id="title"></h3>
            <div class="sub-goals" id="sub-goals"></div>
        </div>
        <button id="nav-btn" class="nav-btn" title="Drill down">›</button>
    </div>
`;

export class GoalItem extends HTMLElement {
    private _subGoals: Goal[] = [];

    static get observedAttributes() {
        return ['data-goal-id', 'data-title', 'data-status'];
    }

    set subGoals(value: Goal[]) {
        this._subGoals = value;
        this.update();
    }

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        this.setupEvents();
        this.update();
    }

    attributeChangedCallback(_name: string, oldValue: string | null, newValue: string | null) {
        if (oldValue === newValue) return;
        this.update();
    }

    private setupEvents() {
        this.shadowRoot!.getElementById('nav-btn')!.addEventListener('click', () => {
            this.dispatchEvent(createGoalNavigateEvent({ id: this.dataset.goalId! }));
        });

        this.shadowRoot!.getElementById('status-indicator')!.addEventListener('click', () => {
            this.dispatchEvent(createGoalChangeStatusEvent({ id: this.dataset.goalId! }));
        });
    }

    private update() {
        const shadow = this.shadowRoot!;
        const titleEl = shadow.getElementById('title');
        if (!titleEl) return;

        titleEl.textContent = this.dataset.title ?? '';
        titleEl.style.viewTransitionName = `title-${this.dataset.goalId}`;

        const statusIndicator = shadow.getElementById('status-indicator')!;
        statusIndicator.className = `status-indicator status-${(this.dataset.status ?? 'ACTIVE').toLowerCase()}`;

        const subGoalsContainer = shadow.getElementById('sub-goals')!;
        subGoalsContainer.replaceChildren();

        this._subGoals.forEach(sub => {
            const cube = document.createElement('goal-cube');
            cube.setAttribute('status', sub.status);
            cube.setAttribute('title', sub.title);
            subGoalsContainer.appendChild(cube);
        });
    }
}

if (!customElements.get('goal-item')) {
    customElements.define('goal-item', GoalItem);
}
