export const GOAL_EVENTS = {
    NAVIGATE: 'goal:navigate',
    NAV_BACK: 'goal:nav-back',
    EDIT_GOAL: 'goal:edit-goal',
    DELETE_GOAL: 'goal:delete-goal',
    CHANGE_STATUS: 'goal:change-status',
} as const;

export interface GoalEventMap {
    [GOAL_EVENTS.NAVIGATE]: { id: string };
    [GOAL_EVENTS.NAV_BACK]: undefined;
    [GOAL_EVENTS.EDIT_GOAL]: { id: string };
    [GOAL_EVENTS.DELETE_GOAL]: { id: string };
    [GOAL_EVENTS.CHANGE_STATUS]: { id: string };
}

export type GoalEvent<K extends keyof GoalEventMap> = CustomEvent<GoalEventMap[K]>;

export function createGoalEvent<K extends keyof GoalEventMap>(
    type: K,
    detail: GoalEventMap[K]
): GoalEvent<K> {
    return new CustomEvent(type, {
        bubbles: true,
        composed: true,
        detail,
    }) as GoalEvent<K>;
}

export const createGoalNavigateEvent = (detail: GoalEventMap[typeof GOAL_EVENTS.NAVIGATE]) => createGoalEvent(GOAL_EVENTS.NAVIGATE, detail);
export const createGoalNavBackEvent = () => createGoalEvent(GOAL_EVENTS.NAV_BACK, undefined);
export const createGoalEditEvent = (detail: GoalEventMap[typeof GOAL_EVENTS.EDIT_GOAL]) => createGoalEvent(GOAL_EVENTS.EDIT_GOAL, detail);
export const createGoalDeleteEvent = (detail: GoalEventMap[typeof GOAL_EVENTS.DELETE_GOAL]) => createGoalEvent(GOAL_EVENTS.DELETE_GOAL, detail);
export const createGoalChangeStatusEvent = (detail: GoalEventMap[typeof GOAL_EVENTS.CHANGE_STATUS]) => createGoalEvent(GOAL_EVENTS.CHANGE_STATUS, detail);

export type GoalNavigateEvent = GoalEvent<typeof GOAL_EVENTS.NAVIGATE>;
export type GoalNavBackEvent = GoalEvent<typeof GOAL_EVENTS.NAV_BACK>;
export type GoalEditEvent = GoalEvent<typeof GOAL_EVENTS.EDIT_GOAL>;
export type GoalDeleteEvent = GoalEvent<typeof GOAL_EVENTS.DELETE_GOAL>;
export type GoalChangeStatusEvent = GoalEvent<typeof GOAL_EVENTS.CHANGE_STATUS>;

declare global {
    interface HTMLElementEventMap {
        [GOAL_EVENTS.NAVIGATE]: GoalNavigateEvent;
        [GOAL_EVENTS.NAV_BACK]: GoalNavBackEvent;
        [GOAL_EVENTS.EDIT_GOAL]: GoalEditEvent;
        [GOAL_EVENTS.DELETE_GOAL]: GoalDeleteEvent;
        [GOAL_EVENTS.CHANGE_STATUS]: GoalChangeStatusEvent;
    }
}
