import type { Goal } from '@motivation/shared';
import { GoalItem } from './goal-item/goal-item.component.js';
import stylesText from './goal-list.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div id="list-container"></div>
`;

const emptyTemplate = document.createElement('template');
emptyTemplate.innerHTML = `
    <div class="empty-state">No goals here yet.</div>
`;

export class GoalList extends HTMLElement {
    private _goals: Goal[] = [];

    set goals(value: Goal[]) {
        this._goals = value;
        this.render();
    }

    get goals() {
        return this._goals;
    }

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        this.render();
    }

    render() {
        const container = this.shadowRoot!.getElementById('list-container')!;
        container.replaceChildren();

        if (this._goals.length === 0) {
            container.appendChild(emptyTemplate.content.cloneNode(true));
            return;
        }

        this._goals.forEach(goal => {
            const item = document.createElement('goal-item') as GoalItem;
            item.dataset.goalId = goal.id;
            item.dataset.title = goal.title;
            item.dataset.description = goal.description ?? '';
            item.dataset.status = goal.status;
            item.subGoals = goal.sub_goals ?? [];
            container.appendChild(item);
        });
    }
}

if (!customElements.get('goal-list')) {
    customElements.define('goal-list', GoalList);
}
