import type { Goal } from '@motivation/shared';
import { GoalService } from '../../services/goal.service.js';
import { GoalNavigator } from './goal-navigator/goal-navigator.component.js';
import { GoalDialogController } from './goal-dialog/goal-dialog.controller.js';
import {
    GOAL_EVENTS,
    type GoalNavigateEvent,
    type GoalNavBackEvent,
    type GoalEditEvent,
    type GoalDeleteEvent,
    type GoalChangeStatusEvent,
} from './goal-events.js';
import './goal-navigator/goal-navigator.component.js';

export class GoalsScreen extends HTMLElement {
    private initialized = false;
    private navigator!: GoalNavigator;
    private dialogController!: GoalDialogController;
    private loadingEl!: HTMLElement;
    private errorEl!: HTMLElement;
    private retryBtn!: HTMLButtonElement;
    private createBtn!: HTMLButtonElement;

    connectedCallback(): void {
        if (!this.initialized) {
            this.initialized = true;
            this.classList.add('view-section');
            this.id = 'goals-view';
            this.buildDom();
            this.wireEvents();
        }
        void this.refresh();
    }

    disconnectedCallback(): void {
        this.dialogController?.destroy();
    }

    /** Test-only: allow deterministic render without hitting the network. */
    renderGoals(goals: Goal[]): void {
        this.navigator.renderGoals(goals);
    }

    private buildDom(): void {
        this.loadingEl = document.createElement('p');
        this.loadingEl.className = 'screen-loading';
        this.loadingEl.textContent = 'Loading goals…';
        this.loadingEl.hidden = true;

        this.errorEl = document.createElement('pre');
        this.errorEl.className = 'screen-error';
        this.errorEl.dataset.testid = 'goals-error';
        this.errorEl.hidden = true;

        this.retryBtn = document.createElement('button');
        this.retryBtn.type = 'button';
        this.retryBtn.className = 'screen-retry';
        this.retryBtn.dataset.testid = 'goals-retry';
        this.retryBtn.textContent = 'Retry';
        this.retryBtn.hidden = true;
        this.retryBtn.addEventListener('click', () => { void this.refresh(); });

        this.navigator = document.createElement('goal-navigator') as GoalNavigator;
        this.navigator.id = 'goal-navigator';

        this.createBtn = document.createElement('button');
        this.createBtn.className = 'fab';
        this.createBtn.title = 'New Goal';
        this.createBtn.textContent = '+';

        this.append(this.loadingEl, this.errorEl, this.retryBtn, this.navigator, this.createBtn);

        this.dialogController = new GoalDialogController(() => this.refresh());
    }

    private wireEvents(): void {
        this.createBtn.addEventListener('click', () => {
            this.dialogController.openGoalDialog(null, this.navigator.currentParentId);
        });

        // Event delegation from child Web Components — scoped to this screen,
        // so no document-level listeners.
        this.addEventListener(GOAL_EVENTS.NAVIGATE, (e: GoalNavigateEvent) => {
            this.navigator.navigateTo(e.detail.id);
        });
        this.addEventListener(GOAL_EVENTS.NAV_BACK, (e: GoalNavBackEvent) => this.navigator.navigateUp());
        this.addEventListener(GOAL_EVENTS.EDIT_GOAL, (e: GoalEditEvent) => {
            const goal = this.navigator.findGoal(this.navigator.allGoals, e.detail.id);
            if (goal) this.dialogController.openGoalDialog(goal);
        });
        this.addEventListener(GOAL_EVENTS.DELETE_GOAL, (e: GoalDeleteEvent) => {
            this.dialogController.openConfirmDelete(e.detail.id);
        });
        this.addEventListener(GOAL_EVENTS.CHANGE_STATUS, (e: GoalChangeStatusEvent) => {
            const goal = this.navigator.findGoal(this.navigator.allGoals, e.detail.id);
            if (goal) this.dialogController.openStatusDialog(goal);
        });
    }

    private async refresh(): Promise<void> {
        this.setLoading();
        try {
            const goals = await GoalService.fetchGoals();
            this.navigator.renderGoals(goals);
            this.clearStatus();
        } catch (err) {
            this.setError(err);
        }
    }

    private setLoading(): void {
        this.loadingEl.hidden = false;
        this.errorEl.hidden = true;
        this.retryBtn.hidden = true;
    }

    private setError(err: unknown): void {
        const message = err instanceof Error ? (err.stack ?? `${err.name}: ${err.message}`) : String(err);
        this.errorEl.textContent = `Failed to load goals\n\n${message}`;
        this.errorEl.hidden = false;
        this.retryBtn.hidden = false;
        this.loadingEl.hidden = true;
    }

    private clearStatus(): void {
        this.loadingEl.hidden = true;
        this.errorEl.hidden = true;
        this.retryBtn.hidden = true;
    }
}

if (!customElements.get('goals-screen')) {
    customElements.define('goals-screen', GoalsScreen);
}
